// CF12 WF_VIRAL_TAG — normalize trigger, idempotency, fetch topic + scenes.
// Prepares batches of ≤50 scenes for downstream Opus scoring.
// Global fetch + $env per MEMORY.md.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const topicId = payload.topic_id;
const force = payload.force === true;

if (!topicId) {
  return [{
    json: {
      success: false,
      error: 'Provide { topic_id }',
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Fetch topic
const topicUrl = `${supabaseUrl}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,seo_title,selected_title,viral_moments,top_3_viral_moments_idx,viral_tagged_at`;
const topics = await sbGet(topicUrl, 'fetch topic');
const topic = Array.isArray(topics) && topics[0] ? topics[0] : null;

if (!topic) {
  return [{ json: { success: false, error: `Topic ${topicId} not found`, http_status: 404, via_webhook: viaWebhook } }];
}

// 2. Idempotency
if (!force && topic.viral_tagged_at) {
  return [{
    json: {
      success: true,
      skipped: true,
      reason: 'Viral moments already tagged (pass force=true to re-tag)',
      topic_id: topicId,
      project_id: topic.project_id,
      viral_moments: topic.viral_moments,
      top_3_viral_moments_idx: topic.top_3_viral_moments_idx,
      viral_tagged_at: topic.viral_tagged_at,
      http_status: 200,
      via_webhook: viaWebhook
    }
  }];
}

const projectId = topic.project_id;

// 3. Fetch project context
let project = {};
try {
  const projArr = await sbGet(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description`, 'fetch project');
  project = (projArr && projArr[0]) || {};
} catch (_) { }

// 4. Fetch scenes
const scenesUrl = `${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&select=scene_number,narration_text,emotional_beat,chapter&order=scene_number.asc&limit=500`;
let scenes = [];
try {
  scenes = await sbGet(scenesUrl, 'fetch scenes');
} catch (e) {
  return [{ json: { success: false, error: `Failed to fetch scenes: ${e.message}`, http_status: 500, via_webhook: viaWebhook } }];
}

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{ json: { success: false, error: 'No scenes found for topic — cannot tag viral moments', http_status: 422, via_webhook: viaWebhook } }];
}

// 5. Build batches — ≤60 scenes in one call, otherwise chunks of 50
const BATCH_SIZE = 50;
const batches = [];
if (scenes.length <= 60) {
  batches.push(scenes);
} else {
  for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
    batches.push(scenes.slice(i, i + BATCH_SIZE));
  }
}

return [{
  json: {
    topic_id: topicId,
    project_id: projectId,
    topic,
    project,
    scenes,
    batches,
    total_batches: batches.length,
    scene_count: scenes.length,
    via_webhook: viaWebhook,
    force,
    started_at: new Date().toISOString()
  }
}];

// Score each batch sequentially via Claude Opus 4.6. Inline backoff per call.
// Merge results, sort by scene_number, derive top_3_viral_moments_idx.

const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const topic = data.topic || {};
const project = data.project || {};
const batches = data.batches || [];
const totalBatches = batches.length;

const seoTitle = topic.selected_title || topic.seo_title || '(untitled)';
const nicheContext = project.niche_description || project.niche || 'general audience';

const VALID_BEATS = ['shock', 'revelation', 'tension', 'payoff', 'setup', 'neutral'];

function clampScore100(n) { const v = Number(n) || 0; return Math.max(0, Math.min(100, Math.round(v))); }

function parseJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch {} }
  return null;
}

async function callClaude(userPrompt, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 4000,
          messages: [{ role: 'user', content: userPrompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, text: body.content?.[0]?.text || '', attempts: attempt };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || 'opus_viral_tag failed', attempts: maxRetries };
}

const allScored = [];
const batchErrors = [];
let totalDurationMs = 0;
let successfulBatches = 0;
const runStart = Date.now();

for (let bi = 0; bi < batches.length; bi++) {
  const batch = batches[bi];
  const scenesBlock = batch
    .map(s => `[${s.scene_number}] ${(s.narration_text || '').slice(0, 600)}`)
    .join('\n\n');

  const prompt = `You are a YouTube Shorts curator. Score each scene's viral potential for clipping into a Short.

Topic: ${seoTitle}
Niche: ${nicheContext}

Scenes (batch ${bi + 1}/${totalBatches}):
${scenesBlock}

For EACH scene, score:
- viral_potential (0-100): does this moment have hook potential that could stand alone?
- shorts_worthiness (0-100): would this work as a 15-60s YouTube Short if clipped with surrounding context?
- emotional_beat: "shock" | "revelation" | "tension" | "payoff" | "setup" | "neutral"
- shareability_hook: one-line description of WHY someone would share this clip

Be strict. Most scenes score 30-55. Rare 85+. 100 means "this IS the Short."

Return ONLY valid JSON:
{
  "scenes": [
    {
      "scene_number": <int>,
      "excerpt": "<first 100 chars of narration>",
      "viral_potential": <int>,
      "shorts_worthiness": <int>,
      "emotional_beat": "<string>",
      "shareability_hook": "<string>"
    }
  ]
}`;

  const batchStart = Date.now();
  const res = await callClaude(prompt, 4);
  totalDurationMs += Date.now() - batchStart;

  if (!res.ok) {
    batchErrors.push({ batch_index: bi, error: res.error });
    // Fallback neutral scoring for this batch
    for (const s of batch) {
      allScored.push({
        scene_number: s.scene_number,
        excerpt: (s.narration_text || '').slice(0, 100),
        viral_potential: 40,
        shorts_worthiness: 40,
        emotional_beat: VALID_BEATS.includes(s.emotional_beat) ? s.emotional_beat : 'neutral',
        shareability_hook: ''
      });
    }
    // Inter-batch spacing on failure
    if (bi + 1 < batches.length) await sleep(1000);
    continue;
  }

  const parsed = parseJson(res.text);
  if (!parsed || !Array.isArray(parsed.scenes)) {
    batchErrors.push({ batch_index: bi, error: 'parse_failed' });
    for (const s of batch) {
      allScored.push({
        scene_number: s.scene_number,
        excerpt: (s.narration_text || '').slice(0, 100),
        viral_potential: 40,
        shorts_worthiness: 40,
        emotional_beat: VALID_BEATS.includes(s.emotional_beat) ? s.emotional_beat : 'neutral',
        shareability_hook: ''
      });
    }
    if (bi + 1 < batches.length) await sleep(1000);
    continue;
  }

  // Index returned scenes by scene_number for coverage check
  const returned = new Map();
  for (const sc of parsed.scenes) {
    const num = Number(sc.scene_number);
    if (!Number.isInteger(num)) continue;
    const beat = VALID_BEATS.includes(sc.emotional_beat) ? sc.emotional_beat : 'neutral';
    returned.set(num, {
      scene_number: num,
      excerpt: String(sc.excerpt || '').slice(0, 200),
      viral_potential: clampScore100(sc.viral_potential),
      shorts_worthiness: clampScore100(sc.shorts_worthiness),
      emotional_beat: beat,
      shareability_hook: String(sc.shareability_hook || '').slice(0, 500)
    });
  }

  // Ensure every input scene in the batch produces an output row
  for (const s of batch) {
    const scored = returned.get(s.scene_number);
    if (scored) {
      // Prefer excerpt with original narration if Claude returned empty
      if (!scored.excerpt) scored.excerpt = (s.narration_text || '').slice(0, 100);
      allScored.push(scored);
    } else {
      allScored.push({
        scene_number: s.scene_number,
        excerpt: (s.narration_text || '').slice(0, 100),
        viral_potential: 40,
        shorts_worthiness: 40,
        emotional_beat: VALID_BEATS.includes(s.emotional_beat) ? s.emotional_beat : 'neutral',
        shareability_hook: ''
      });
    }
  }

  successfulBatches += 1;
  if (bi + 1 < batches.length) await sleep(1000);
}

// Sort merged results by scene_number
allScored.sort((a, b) => a.scene_number - b.scene_number);

// top_3_viral_moments_idx: indexes into allScored, ranked by shorts_worthiness then viral_potential
const indexed = allScored.map((s, i) => ({ i, sw: s.shorts_worthiness, vp: s.viral_potential }));
indexed.sort((a, b) => (b.sw - a.sw) || (b.vp - a.vp));
const top3 = indexed.slice(0, 3).map(x => x.i);

// Cost estimate: ~$0.05 per batch
const costUsd = Math.round(successfulBatches * 0.05 * 1000) / 1000;
const anyOk = successfulBatches > 0;
const allOk = successfulBatches === totalBatches;

return [{
  json: {
    ...data,
    viral_moments: allScored,
    top_3_viral_moments_idx: top3,
    opus_all_ok: allOk,
    opus_any_ok: anyOk,
    batch_errors: batchErrors,
    successful_batches: successfulBatches,
    total_batches_run: totalBatches,
    opus_duration_ms: totalDurationMs,
    opus_cost_usd: costUsd,
    total_run_ms: Date.now() - runStart
  }
}];

