    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
