  if (bi + 1 < batches.length) await sleep(1000);
}

// Sort merged results by scene_number
allScored.sort((a, b) => a.scene_number - b.scene_number);

// top_3_viral_moments_idx: indexes into allScored, ranked by shorts_worthiness then viral_potential
const indexed = allScored.map((s, i) => ({ i, sw: s.shorts_worthiness, vp: s.viral_potential }));
indexed.sort((a, b) => (b.sw - a.sw) || (b.vp - a.vp));
const top3 = indexed.slice(0, 3).map(x => x.i);

// Cost estimate: ~$0.05 per batch
const costUsd = Math.round(successfulBatches * 0.05 * 1000) / 1000;
const anyOk = successfulBatches > 0;
const allOk = successfulBatches === totalBatches;

return [{
  json: {
    ...data,
    viral_moments: allScored,
    top_3_viral_moments_idx: top3,
    opus_all_ok: allOk,
    opus_any_ok: anyOk,
    batch_errors: batchErrors,
    successful_batches: successfulBatches,
    total_batches_run: totalBatches,
    opus_duration_ms: totalDurationMs,
    opus_cost_usd: costUsd,
    total_run_ms: Date.now() - runStart
  }
}];

// PATCH topic with viral_moments + top_3_viral_moments_idx. Log to production_logs.
const data = $input.first().json;
if (data.success === false) return [{ json: data }];
if (data.skipped) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const projectId = data.project_id;
const nowIso = new Date().toISOString();

const patch = {
  viral_moments: data.viral_moments,
  top_3_viral_moments_idx: data.top_3_viral_moments_idx,
  viral_tagged_at: nowIso
};

let patchError = null;
try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  patchError = e.message;
}

let logStatus;
if (patchError) logStatus = 'partial';
else if (data.opus_all_ok) logStatus = 'success';
else if (data.opus_any_ok) logStatus = 'partial';
else logStatus = 'fallback';

// production_logs
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'viral_tag',
      scene_number: null,
      action: 'opus_scene_score',
      status: logStatus,
      duration_ms: data.opus_duration_ms || 0,
      cost_usd: data.opus_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !patchError,
    topic_id: topicId,
    project_id: projectId,
    viral_moments: data.viral_moments,
    top_3_viral_moments_idx: data.top_3_viral_moments_idx,
    viral_tagged_at: nowIso,
    scene_count: data.scene_count,
    successful_batches: data.successful_batches,
    total_batches: data.total_batches_run,
    batch_errors: data.batch_errors,
    opus_all_ok: data.opus_all_ok,
    opus_cost_usd: data.opus_cost_usd,
    patch_error: patchError,
    http_status: patchError ? 500 : 200,
    via_webhook: data.via_webhook
  }
}];
